-- ==========================================
-- 2. TABLA MAESTRA DE PRODUCTOS
-- ==========================================

CREATE TABLE productos (
    id INTEGER PRIMARY KEY,
    producto VARCHAR(255) NOT NULL, -- Nombre comercial
    presentacion VARCHAR(20), -- Capacidad o unidad (ej. '750ml', '20')
    alias VARCHAR(30), -- Nombre corto opcional
    id_tipo INTEGER REFERENCES tipos_producto(id), -- Clasificacion (tequila, whisky, ron, etc.)
    precio_referencia NUMERIC(10, 2), -- Precio de referencia de mercado
    url_image TEXT, -- Enlace a la imagen del producto
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW(),
    
    -- Restricción para evitar duplicados del mismo producto en la misma presentación
    CONSTRAINT uq_nombre_presentacion UNIQUE (producto, presentacion)
);

